 159.703 1415.57 159.631 1414.82 159.83L1401.84 163.263C1394.57 165.184 1386.79 162.915 1382.01 157.109C1378.99 153.434 1376.43 150.057 1376.21 148.95C1375.96 147.715 1374.02 142.335 1371.91 136.704C1369.36 129.895 1370.62 122.231 1375.28 116.654L1386.29 103.49L1389.35 100.435C1391.15 98.6428 1390.5 95.5924 1388.13 94.6835C1386.99 94.2442 1385.69 94.4366 1384.73 95.1905L1357.77 116.185C1354.25 118.92 1349.93 120.406 1345.48 120.406H1324.24C1319.99 120.406 1316.07 118.091 1314.01 114.364C1312.42 111.479 1309.68 109.4 1306.48 108.639L1248.91 94.9774C1246.13 94.3173 1243.52 93.0686 1241.26 91.3154L1194.31 54.8596Z',
    ],
    labelX: 1250,
    labelY: 180,
    previewImage: '/island/n1.png',
  },
}

const router = useRouter()
const progressStore = useProgressStore()
const previewIslandId = ref<LevelId>(progressStore.progress.selectedLevel ?? 'n5')

const mapLevels = computed(() => {
  return jlptLevels.map((level) => ({
    ...level,
    svg: islandSvgMap[level.id],
  }))
})

const previewIsland = computed<LevelConfig>(() => {
  return jlptLevels.find((level) => level.id === previewIslandId.value) ?? jlptLevels[0]
})

const previewCompletedCount = computed(() => {
  return previewIsland.value.categories.filter((category) => {
    const categoryState = progressStore.progress.levelScores[previewIsland.value.id]?.categories?.[category.id]
    return categoryState?.completed
  }).length
})

const previewMastery = computed(() => progressStore.getLevelScore(previewIsland.value.id))

function getIslandStatus(levelId: LevelId): 'completed' | 'unlocked' | 'locked' {
  if (progressStore.isCompleted(levelId)) {
    return 'completed'
  }

  if (progressStore.isUnlocked(levelId)) {
    return 'unlocked'
  }

  return 'locked'
}

function setPreview(levelId: LevelId): void {
  previewIslandId.value = levelId
}

function openIsland(levelId: LevelId): void {
  if (!progressStore.isUnlocked(levelId)) {
    return
  }

  progressStore.selectLevel(levelId)
  router.push(`/island/${levelId}`)
}
</script>

<template>
  <AppShell>
    <section class="map-screen map-screen--image">
      <div class="map-stage map-stage--image">
        <div class="map-head map-head--image">
          <div>
            <p class="eyebrow">Peta Progress</p>
            <h1 class="title">Pilih pulau JLPT-mu</h1>
            <p class="subtitle">
              Petualangan Belajar JLPT menunggu kamuhhhh (semoga lulus beneran yh)
            </p>
          </div>

          <div class="map-head__badges">
            <span class="badge">{{ progressStore.totalUnlocked }} level terbuka</span>
            <span class="badge">{{ progressStore.totalCompleted }} level tuntas</span>
          </div>
        </div>

        <div class="map-showcase">
          <div class="map-showcase__visual panel map-showcase__visual--svg">
            <svg
              class="jlpt-map-svg"
              viewBox="0 0 1440 1024"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              aria-label="JLPT island map"
            >
              <g transform="translate(-235 115) scale(1.28)">
                <g
                  v-for="level in mapLevels"
                  :key="level.id"
                  class="jlpt-map-region"
                  :class="[
                    `jlpt-map-region--${getIslandStatus(level.id)}`,
                    { 'jlpt-map-region--active': previewIsland.id === level.id },
                  ]"
                  tabindex="0"
                  role="button"
                  :aria-label="`Buka ${level.label}`"
                  @mouseenter="setPreview(level.id)"
                  @focus="setPreview(level.id)"
                  @click="openIsland(level.id)"
                  @keydown.enter.prevent="openIsland(level.id)"
                  @keydown.space.prevent="openIsland(level.id)"
                >
                  <path
                    v-for="(shapePath, pathIndex) in level.svg.paths"
                    :key="`${level.id}-${pathIndex}`"
                    class="jlpt-map-region__shape"
                    :d="shapePath"
                    :fill="level.themeColor"
                  />
                  <text
                    class="jlpt-map-region__label"
                    :x="level.svg.labelX"
                    :y="level.svg.labelY"
                  >
                    {{ level.label }}
                  </text>
                </g>
              </g>
            </svg>

            <div class="map-showcase__hint">
              <strong>{{ previewIsland.label }}</strong>
              <span>{{ progressStore.isUnlocked(previewIsland.id) ? 'Klik pulau untuk masuk ke level ini' : 'Pulau ini masih terkunci, tapi sudah bisa dipreview' }}</span>
            </div>
          </div>

          <aside class="map-preview panel">
            <p class="eyebrow">Preview Level</p>
            <div class="map-preview__hero">
              <img
                class="map-preview__island"
                :src="islandSvgMap[previewIsland.id].previewImage"
                :alt="`Preview pulau ${previewIsland.label}`"
              />
            </div>

            <div class="map-preview__body">
              <div class="map-preview__title-row">
                <div>
                  <h2 class="map-preview__title">{{ previewIsland.label }}</h2>
                  <p class="small-note">{{ previewIsland.name }}</p>
                </div>
                <span class="badge" :class="`map-status-badge map-status-badge--${getIslandStatus(previewIsland.id)}`">
                  {{
                    getIslandStatus(previewIsland.id) === 'completed'
                      ? 'Tuntas'
                      : getIslandStatus(previewIsland.id) === 'unlocked'
                        ? 'Terbuka'
                        : 'Terkunci'
                  }}
                </span>
              </div>

              <p class="map-preview__status">{{ previewIsland.statusLabel }}</p>

              <div class="progress-bar" style="margin-top: 16px;">
                <span :style="{ width: `${previewMastery}%` }" />
              </div>
              <p class="small-note" style="margin-top: 8px;">
                Mastery {{ previewMastery }}% • {{ previewCompletedCount }} / {{ previewIsland.categories.length }} kategori selesai
              </p>

              <div class="map-preview__categories">
                <div
                  v-for="category in previewIsland.categories"
                  :key="category.id"
                  class="map-preview__category"
                >
                  <strong>{{ category.title }}</strong>
                  <span>{{ category.questions }} soal</span>
                </div>
              </div>

              <div class="button-row" style="margin-top: 20px;">
                <button
                  class="btn btn-primary"
                  type="button"
                  :disabled="!progressStore.isUnlocked(previewIsland.id)"
                  @click="openIsland(previewIsland.id)"
                >
                  Masuk {{ previewIsland.label }}
                </button>
              </div>
            </div>
          </aside>
        </div>

        <div class="map-level-strip">
          <button
            v-for="level in mapLevels"
            :key="`${level.id}-chip`"
            class="map-level-chip"
            :class="[
              `map-level-chip--${getIslandStatus(level.id)}`,
              { 'map-level-chip--active': previewIsland.id === level.id },
            ]"
            type="button"
            @mouseenter="setPreview(level.id)"
            @focus="setPreview(level.id)"
            @click="openIsland(level.id)"
          >
            <strong>{{ level.label }}</strong>
            <span>{{ level.name }}</span>
          </button>
        </div>
      </div>
    </section>
  </AppShell>
</template>
